                                       const at::Tensor& w,
                                       const at::Tensor& b,
                                       const at::Tensor& divisor) {
    TORCH_CHECK(x.dim() == 2, "x must be 2D [M, K]");
    TORCH_CHECK(w.dim() == 2, "w must be 2D [N, K]");
    TORCH_CHECK(b.dim() == 1, "b must be 1D [N]");
    TORCH_CHECK(divisor.numel() == 1, "divisor must be a scalar tensor");

    auto M = x.size(0);
    auto N = w.size(0);
    at::Tensor result = at::empty({M, N}, x.options());
    EXEC_NPU_CMD(aclnnMatmulDivideGeluCustom, x, w, b, divisor, result);
    return result;
}

